import React, { useState } from 'react';

function Header() {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const toggleMenu = () => {
    setIsMenuOpen(!isMenuOpen);
  };

  const scrollToSection = (id) => {
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth' });
    }
    setIsMenuOpen(false);
  };

  return (
    <header className="sticky top-0 z-50 bg-white shadow-sm border-b border-gray-200">
      <nav className="max-w-2xl mx-auto px-4 py-3 flex justify-between items-center">
        <button onClick={() => scrollToSection('hero')} className="text-xl font-bold text-gray-900 hover:text-blue-600 transition">
          Dip<span className="text-blue-600">.</span>
        </button>

        {/* Desktop Menu */}
        <div className="hidden md:flex gap-6">
          <button onClick={() => scrollToSection('hero')} className="text-sm font-medium text-gray-700 hover:text-blue-600 transition">
            Profile
          </button>
          <button onClick={() => scrollToSection('experience')} className="text-sm font-medium text-gray-700 hover:text-blue-600 transition">
            Experience
          </button>
          <button onClick={() => scrollToSection('skills')} className="text-sm font-medium text-gray-700 hover:text-blue-600 transition">
            Skills
          </button>
          <button onClick={() => scrollToSection('education')} className="text-sm font-medium text-gray-700 hover:text-blue-600 transition">
            Education
          </button>
          <button onClick={() => scrollToSection('contact')} className="text-sm font-medium text-gray-700 hover:text-blue-600 transition">
            Contact
          </button>
        </div>

        {/* Mobile Menu Toggle */}
        <button className="md:hidden" onClick={toggleMenu}>
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
          </svg>
        </button>
      </nav>

      {/* Mobile Menu */}
      {isMenuOpen && (
        <div className="md:hidden bg-white border-t border-gray-200">
          <div className="flex flex-col gap-2 px-4 py-3">
            <button onClick={() => scrollToSection('hero')} className="text-gray-700 hover:text-blue-600 transition text-left py-2 text-sm font-medium">
              Profile
            </button>
            <button onClick={() => scrollToSection('experience')} className="text-gray-700 hover:text-blue-600 transition text-left py-2 text-sm font-medium">
              Experience
            </button>
            <button onClick={() => scrollToSection('skills')} className="text-gray-700 hover:text-blue-600 transition text-left py-2 text-sm font-medium">
              Skills
            </button>
            <button onClick={() => scrollToSection('education')} className="text-gray-700 hover:text-blue-600 transition text-left py-2 text-sm font-medium">
              Education
            </button>
            <button onClick={() => scrollToSection('contact')} className="text-gray-700 hover:text-blue-600 transition text-left py-2 text-sm font-medium">
              Contact
            </button>
          </div>
        </div>
      )}
    </header>
  );
}

export default Header;
